// Build evergreen Perplexity prompts from the live fetched pricing table.
// Nothing about the table is hardcoded — the model list derives from the fetch at runtime.
const raw = $input.first().json;
const table = typeof raw === 'string' ? JSON.parse(raw)
  : (typeof raw.data === 'string' ? JSON.parse(raw.data) : raw);

const SKIP = new Set(['$schema', 'versionedAt']);
const providers = Object.keys(table).filter(k => !SKIP.has(k) && table[k] && typeof table[k] === 'object');

const lineup = {};
for (const p of providers) lineup[p] = Object.keys(table[p]);

const today = new Date().toISOString().slice(0, 10);

const modelLines = providers.map(p => p + ': ' + lineup[p].join(', ')).join('\n');
const driftPrompt =
  'Today is ' + today + '. Return ONLY a JSON object (no prose, no markdown) giving the CURRENT official list ' +
  'price in USD per 1,000,000 tokens for each model below. Shape exactly: ' +
  '{"provider":{"model-id":{"input":<number>,"output":<number>}}}. ' +
  'If you cannot find a reliable current price for a model, set its value to null. Models:\n' + modelLines;

const newModelsPrompt =
  'Today is ' + today + '. List the latest GENERALLY-AVAILABLE flagship and workhorse LLMs and their ' +
  'per-1,000,000-token USD input/output pricing from these providers: ' + providers.join(', ') + '. ' +
  'Return ONLY a JSON object of shape {"provider":{"model-id":{"input":<number>,"output":<number>}}}. ' +
  'Include only models that are generally available today.';

return [{ json: { table, providers, lineup, today, driftPrompt, newModelsPrompt } }];

// Deterministic comparison — NO LLM. Iterates EVERY model key in the fetched table (old + new alike).
const THRESHOLD = 5; // percent, on input OR output
const bq = $('Build queries').first().json;
const table = bq.table;
const providers = bq.providers;
const today = bq.today;

// Robust JSON extraction from a probabilistic Perplexity text response.
function extractJson(content){
  if (content == null) return {};
  if (typeof content === 'object') return content;
  const s = String(content);
  const a = s.indexOf('{');
  const b = s.lastIndexOf('}');
  if (a === -1 || b === -1) return {};
  try { return JSON.parse(s.slice(a, b + 1)); } catch (e) { return {}; }
}

const detected = extractJson($('Perplexity — drift').first().json?.choices?.[0]?.message?.content);
const newLineup = extractJson($('Perplexity — new models').first().json?.choices?.[0]?.message?.content);

const results = [];
for (const provider of providers){
  for (const model of Object.keys(table[provider])){
    const t = table[provider][model];
    const tIn = t.inputPer1M;
    const tOut = t.outputPer1M;
    const d = detected?.[provider]?.[model];
    if (!d || d.input == null || d.output == null){
      results.push({ provider, model, classification: 'UNVERIFIABLE', tIn, tOut });
      continue;
    }
    const dIn = Number(d.input);
    const dOut = Number(d.output);
    const deltaIn = tIn ? Math.abs(dIn - tIn) / tIn * 100 : 0;
    const deltaOut = tOut ? Math.abs(dOut - tOut) / tOut * 100 : 0;
    const drift = deltaIn >= THRESHOLD || deltaOut >= THRESHOLD;
    results.push({ provider, model, classification: drift ? 'DRIFT' : 'MATCH',
      tIn, tOut, dIn, dOut, deltaIn: +deltaIn.toFixed(1), deltaOut: +deltaOut.toFixed(1) });
  }
}

// New-model candidates: present in Perplexity's current lineup, absent as a key in the table.
const candidates = [];
for (const provider of Object.keys(newLineup || {})){
  const known = table[provider] || {};
  for (const model of Object.keys(newLineup[provider] || {})){
    if (!(model in known)){
      const p = newLineup[provider][model] || {};
      candidates.push({ provider, model, input: p.input ?? null, output: p.output ?? null });
    }
  }
}

const drifted = results.filter(r => r.classification === 'DRIFT');
const unverifiable = results.filter(r => r.classification === 'UNVERIFIABLE');
const verified = results.filter(r => r.classification === 'MATCH');
const action = drifted.length > 0 || candidates.length > 0;

const emoji = action ? '⚠️' : '✅';
const status = action ? 'Pending' : 'Completed';
const title = action
  ? emoji + ' llm-pricing drift ' + today + ' — drift / new models (' + (drifted.length + candidates.length) + ')'
  : emoji + ' llm-pricing drift ' + today + ' — no drift';
const summary = 'versionedAt ' + table.versionedAt + '; ' + verified.length + ' verified, ' +
  unverifiable.length + ' unverifiable; ' + drifted.length + ' drifted; ' + candidates.length + ' new';

let body = '';
if (drifted.length){
  body += 'DRIFTED MODELS (provider / model / table in→out / detected in→out / delta%)\n';
  for (const r of drifted)
    body += r.provider + ' / ' + r.model + ' / $' + r.tIn + '->$' + r.tOut + ' / $' + r.dIn + '->$' + r.dOut +
      ' / in ' + r.deltaIn + '% out ' + r.deltaOut + '%\n';
  body += '\n';
}
if (candidates.length){
  body += 'NEW-MODEL CANDIDATES (provider / model / detected in->out)\n';
  for (const c of candidates) body += c.provider + ' / ' + c.model + ' / $' + c.input + '->$' + c.output + '\n';
  body += '\n';
}
if (unverifiable.length)
  body += 'UNVERIFIABLE: ' + unverifiable.map(u => u.provider + '/' + u.model).join(', ') + '\n\n';

body += 'Back-compat: table updates never delete existing model keys — older models stay supported and are ' +
  'repriced (not removed) when they drift. Perplexity pricing is probabilistic — verify against official ' +
  'provider pages before any table edit.';

return [{ json: {
  title,
  status,
  project: 'dlabs-toolkit',
  job: 'llm-pricing drift',
  details: summary + '\n\n' + body
} }];
